import React, { useRef, useState, useMemo } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, Quaternion, MathUtils, Mesh } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

// 状态机定义
type ShipState = 'PLANNING' | 'TAKEOFF' | 'TRAVELING' | 'INSERTING' | 'ORBITING' | 'LEAVING' | 'COMPLETED';

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);
  const flameRef = useRef<Mesh>(null);

  // UI 状态
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [missionProgress, setMissionProgress] = useState({ current: 0, total: 0, targetName: '' });

  // 物理与逻辑 Refs
  const stateRef = useRef<ShipState>('PLANNING');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // 核心运动变量
  const velocityRef = useRef(new Vector3());
  const positionRef = useRef(new Vector3());
  const targetPosRef = useRef(new Vector3());
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const totalOrbitTraveledRef = useRef(0);
  const smoothingRef = useRef(new Vector3()); // 用于相机平滑

  // 参数配置
  const MAX_CRUISE_SPEED = 0.5; // 单位时间位移
  const ACCELERATION = 0.01;
  const DECELERATION_DIST = 40; // 开始减速的距离
  const BANKING_INTENSITY = 1.2; // 倾斜强度

  // 任务生成：选取一条有趣的星际航线
  const generateMission = () => {
     const candidates = PLANETS.filter(p => p.id !== 'mercury').map(p => p.id);
     const mission: string[] = [];
     let last = 'earth';
     for (let i = 0; i < 4; i++) {
        let next = candidates[Math.floor(Math.random() * candidates.length)];
        while (next === last) next = candidates[Math.floor(Math.random() * candidates.length)];
        mission.push(next);
        last = next;
     }
     mission.push('earth');
     return mission;
  };

  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 15;
     return p.hasRings ? p.size * 2.8 + 1.5 : p.size * 2.2 + 2.0;
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;
    const dt = delta * 60; // 标准化帧率影响

    // 0. 初始化
    if (!initializedRef.current) {
      const earth = planetRefs.current['earth'];
      if (earth) {
        earth.getWorldPosition(positionRef.current);
        positionRef.current.y += 5; // 稍微偏离地心
        groupRef.current.position.copy(positionRef.current);
        initializedRef.current = true;
        stateRef.current = 'PLANNING';
      }
      return;
    }

    // 1. 状态机逻辑
    if (stateRef.current === 'PLANNING') {
       missionQueueRef.current = generateMission();
       stateRef.current = 'LEAVING';
       return;
    }

    // 更新目标位置
    if (currentTargetIdRef.current && planetRefs.current[currentTargetIdRef.current]) {
      planetRefs.current[currentTargetIdRef.current].getWorldPosition(targetPosRef.current);
    }

    const currentPos = groupRef.current.position;
    let desiredVelocity = new Vector3();
    let steering = new Vector3();

    switch (stateRef.current) {
      case 'LEAVING':
        // 飞离当前引力井，寻找下一个目标
        if (missionQueueRef.current.length > 0) {
           const nextId = missionQueueRef.current.shift()!;
           currentTargetIdRef.current = nextId;
           const pData = PLANETS.find(p => p.id === nextId) || { name: nextId };
           setMissionProgress(prev => ({ current: prev.current + 1, total: 5, targetName: pData.name }));
           stateRef.current = 'TRAVELING';
        } else {
           stateRef.current = 'COMPLETED';
           onMissionComplete();
        }
        break;

      case 'TRAVELING':
        const distToPlanet = currentPos.distanceTo(targetPosRef.current);
        const radius = getSafeOrbitRadius(currentTargetIdRef.current!);

        // 计算目标：切向切入点
        const toTarget = new Vector3().subVectors(targetPosRef.current, currentPos).normalize();
        const tangentOffset = new Vector3(-toTarget.z, 0, toTarget.x).multiplyScalar(radius);
        const entryPoint = new Vector3().addVectors(targetPosRef.current, tangentOffset);

        const distToEntry = currentPos.distanceTo(entryPoint);

        // 到达判定
        if (distToEntry < 2) {
           stateRef.current = 'INSERTING';
           orbitRadiusRef.current = radius;
           const rel = new Vector3().subVectors(currentPos, targetPosRef.current);
           orbitAngleRef.current = Math.atan2(rel.z, rel.x);
           totalOrbitTraveledRef.current = 0;
           break;
        }

        // 速度管理：接近减速
        const speed = distToEntry < DECELERATION_DIST 
          ? MathUtils.lerp(0.1, MAX_CRUISE_SPEED, distToEntry / DECELERATION_DIST)
          : MAX_CRUISE_SPEED;

        desiredVelocity.subVectors(entryPoint, currentPos).normalize().multiplyScalar(speed);
        steering.subVectors(desiredVelocity, velocityRef.current).multiplyScalar(0.05 * dt);
        velocityRef.current.add(steering);
        break;

      case 'INSERTING':
      case 'ORBITING':
        // 轨道环绕逻辑
        const orbitSpeed = 0.12; 
        orbitAngleRef.current += (orbitSpeed / orbitRadiusRef.current) * delta * 15;
        totalOrbitTraveledRef.current += (orbitSpeed / orbitRadiusRef.current) * delta * 15;

        const nextX = targetPosRef.current.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current;
        const nextZ = targetPosRef.current.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current;
        const nextY = targetPosRef.current.y;

        const nextPos = new Vector3(nextX, nextY, nextZ);
        velocityRef.current.subVectors(nextPos, currentPos); // 计算当前的瞬时速度用于方向

        if (totalOrbitTraveledRef.current > Math.PI * 2.2) {
          stateRef.current = 'LEAVING';
        }
        break;
    }

    // 2. 应用物理位移
    if (stateRef.current === 'ORBITING' || stateRef.current === 'INSERTING') {
      // 轨道内使用绝对坐标更新以保证圆度
      const orbitPos = new Vector3(
        targetPosRef.current.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current,
        targetPosRef.current.y,
        targetPosRef.current.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current
      );
      groupRef.current.position.copy(orbitPos);
    } else {
      groupRef.current.position.add(velocityRef.current);
    }

    // 3. 转向与银行角 (Banking)
    if (velocityRef.current.lengthSq() > 0.0001) {
       const lookTarget = new Vector3().addVectors(groupRef.current.position, velocityRef.current);

       // 平滑转向
       const dummy = new Object3D();
       dummy.position.copy(groupRef.current.position);
       dummy.lookAt(lookTarget);
       groupRef.current.quaternion.slerp(dummy.quaternion, 0.1 * dt);

       // 银行角计算：根据角速度差
       if (shipModelRef.current) {
          const isOrbiting = stateRef.current === 'ORBITING' || stateRef.current === 'INSERTING';
          const targetRoll = isOrbiting ? -0.8 : 0; // 环绕时固定侧倾，航行时根据转向
          shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, targetRoll, 0.05 * dt);
       }
    }

    // 4. 引擎火焰动态
    if (flameRef.current) {
       const thrust = velocityRef.current.length() / MAX_CRUISE_SPEED;
       flameRef.current.scale.set(1, thrust * 1.5 + 0.5, 1);
       (flameRef.current.material as any).opacity = 0.4 + thrust * 0.4;
    }

    // 5. 相机平稳跟随 (Spring Arm)
    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion);
    const camTargetPos = currentPos.clone().add(shipForward.clone().multiplyScalar(-18)).add(new Vector3(0, 6, 0));
    state.camera.position.lerp(camTargetPos, 0.1 * dt);

    const lookAtPoint = currentPos.clone().add(shipForward.clone().multiplyScalar(10));
    state.camera.lookAt(lookAtPoint);

    // 更新 UI 速度
    setCurrentSpeedDisplay(Math.round(velocityRef.current.length() * 50000));
  });

  const tName = missionProgress.targetName;

  return (
    <group ref={groupRef}>
      {/* 飞行 HUD */}
      <Html position={[2.5, 0, 0]} transform sprite center>
        <div className="flex flex-col items-start pointer-events-none select-none gap-2 bg-black/40 backdrop-blur-md p-3 border-l-4 border-cyan-400 skew-x-[-12deg]">
           <div className="flex flex-col">
              <span className="text-[10px] text-cyan-300 font-mono tracking-tighter uppercase">Space Velocity</span>
              <div className="text-2xl font-black text-white font-mono italic">
                 {currentSpeedDisplay.toLocaleString()}<span className="text-xs not-italic ml-1 opacity-70">KM/H</span>
              </div>
           </div>
           <div className="h-[1px] w-full bg-white/20 my-1"></div>
           <div className="flex flex-col">
              <span className="text-[10px] text-blue-300 font-mono tracking-tighter uppercase">Destination</span>
              <div className="text-sm font-bold text-white">
                 {tName.split(' ')[0] || "计算中..."}
                 <span className="ml-2 text-[10px] text-white/50">TRACKING</span>
              </div>
           </div>
        </div>
      </Html>

