          <mesh position={[0, 1.3, 0]}>
            <coneGeometry args={[0.4, 0.8, 32]} />
            <meshPhysicalMaterial color="#f8fafc" metalness={0.9} />
          </mesh>

          {/* 尾翼 */}
          <mesh position={[-0.5, -0.6, 0]} rotation={[0, 0, 0.1]}>
            <boxGeometry args={[0.4, 0.7, 0.05]} />
            <meshStandardMaterial color="#1e293b" />
          </mesh>
          <mesh position={[0.5, -0.6, 0]} rotation={[0, 0, -0.1]}>
            <boxGeometry args={[0.4, 0.7, 0.05]} />
            <meshStandardMaterial color="#1e293b" />
          </mesh>

          {/* 引擎火焰 */}
          <mesh ref={flameRef} position={[0, -1.3, 0]}>
            <cylinderGeometry args={[0.2, 0, 1.5, 16, 1, true]} />
            <meshBasicMaterial color="#06b6d4" transparent opacity={0.8} blending={AdditiveBlending} side={DoubleSide} />
          </mesh>

          <pointLight position={[0, -1.5, 0]} color="#22d3ee" intensity={5} distance={10} />
        </group>

        {/* 尾迹 */}
        <group position={[0, 0, -1]}>
           <Trail width={0.6} length={12} color="#22d3ee" attenuation={(t) => t * t} />
        </group>
      </group>
    </group>
  );
};

