import React, { useRef, useState, useEffect } from 'react';
import { useFrame } from '@react-three/fiber';
import { Vector3, Group, Object3D, AdditiveBlending, DoubleSide, Quaternion, MathUtils, Mesh } from 'three';
import { Trail, Html, Text } from '@react-three/drei';
import { PLANETS } from '../constants';

interface StarshipProps {
  planetRefs: React.MutableRefObject<{ [key: string]: Object3D }>;
  onMissionComplete: () => void;
}

// 状态机定义
type ShipState = 'PLANNING' | 'TRAVELING' | 'ORBITING' | 'LEAVING' | 'COMPLETED';

export const Starship: React.FC<StarshipProps> = ({ planetRefs, onMissionComplete }) => {
  const groupRef = useRef<Group>(null);
  const shipModelRef = useRef<Group>(null);

  // UI 状态
  const [currentSpeedDisplay, setCurrentSpeedDisplay] = useState(0);
  const [missionProgress, setMissionProgress] = useState({ current: 0, total: 0, targetName: '' });

  // 核心逻辑 Refs
  const stateRef = useRef<ShipState>('PLANNING');
  const initializedRef = useRef(false);
  const missionQueueRef = useRef<string[]>([]);
  const currentTargetIdRef = useRef<string | null>(null);

  // 动力学变量
  const currentSpeedRef = useRef(0);
  const orbitAngleRef = useRef(0);
  const orbitRadiusRef = useRef(15);
  const totalOrbitTraveledRef = useRef(0);
  const exitVectorRef = useRef(new Vector3());
  const leavingTimeRef = useRef(0);

  // 物理常量 (1单位 = 1000 KM/H)
  const CRUISE_SPEED = 10.0; 
  const ORBIT_SPEED = 6.0;   
  const DECEL_DISTANCE = 50.0; // 开始减速的距离

  // 航线生成
  const generateMission = () => {
     const candidates = PLANETS.filter(p => p.id !== 'mercury').map(p => p.id);
     const mission: string[] = [];
     let lastPlanet = 'earth';
     for (let i = 0; i < 4; i++) {
        let next = candidates[Math.floor(Math.random() * candidates.length)];
        while (next === lastPlanet) next = candidates[Math.floor(Math.random() * candidates.length)];
        mission.push(next);
        lastPlanet = next;
     }
     mission.push('earth');
     return mission;
  };

  const getSafeOrbitRadius = (id: string) => {
     const p = PLANETS.find(x => x.id === id);
     if (!p) return 12;
     return p.hasRings ? p.size * 2.6 + 2.0 : p.size * 2.2 + 2.0;
  };

  useFrame((state, delta) => {
    if (!groupRef.current) return;

    // 0. 初始化
    if (!initializedRef.current) {
      const earthObj = planetRefs.current['earth'];
      if (earthObj) {
        const startPos = new Vector3();
        earthObj.getWorldPosition(startPos);
        if (startPos.lengthSq() > 1) {
             startPos.y += 15.0; 
             startPos.x += 15.0; 
             groupRef.current.position.copy(startPos);
             initializedRef.current = true;
             stateRef.current = 'PLANNING';
        }
      }
      return; 
    }

    // 1. 任务规划
    if (stateRef.current === 'PLANNING') {
       missionQueueRef.current = generateMission();
       stateRef.current = 'LEAVING';
       exitVectorRef.current.set(1, 0, 1).normalize();
       return;
    }

    // 2. 状态驱动
    const currentPos = groupRef.current.position.clone();
    let targetObj: Object3D | null = null;
    let targetPos = new Vector3();

    if (currentTargetIdRef.current && planetRefs.current[currentTargetIdRef.current]) {
      targetObj = planetRefs.current[currentTargetIdRef.current];
      targetObj.getWorldPosition(targetPos);
    }

    switch (stateRef.current) {
      case 'LEAVING':
        leavingTimeRef.current += delta;
        // 平滑加速回巡航速度
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, CRUISE_SPEED, delta * 1.5);
        groupRef.current.position.add(exitVectorRef.current.clone().multiplyScalar(currentSpeedRef.current * delta));

        // 银行角归零
        if (shipModelRef.current) shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, 0, delta * 2);

        if (leavingTimeRef.current > 1.2 && missionQueueRef.current.length > 0) {
           const nextId = missionQueueRef.current.shift()!;
           currentTargetIdRef.current = nextId;
           setMissionProgress(prev => ({ 
               current: prev.current + 1, total: 5, 
               targetName: PLANETS.find(p => p.id === nextId)?.name || nextId 
           }));
           stateRef.current = 'TRAVELING';
        } else if (leavingTimeRef.current > 1.2 && missionQueueRef.current.length === 0) {
           onMissionComplete();
        }
        break;

      case 'TRAVELING':
        if (!targetObj) { stateRef.current = 'LEAVING'; break; }

        const orbitRadius = getSafeOrbitRadius(currentTargetIdRef.current!);
        const dirToPlanet = new Vector3().subVectors(targetPos, currentPos).normalize();

        // 计算切向入轨点 (Tangential Entry Point)
        // 我们希望在轨道边缘切向滑入，而不是直冲球心
        const tangentOffset = new Vector3(-dirToPlanet.z, 0, dirToPlanet.x).multiplyScalar(orbitRadius);
        const entryPoint = new Vector3().addVectors(targetPos, tangentOffset);

        const distToEntry = currentPos.distanceTo(entryPoint);

        // --- 核心逻辑：均匀减速 ---
        // 如果距离入轨点小于 DECEL_DISTANCE，速度从 CRUISE 平滑减至 ORBIT
        let targetSpeed = CRUISE_SPEED;
        if (distToEntry < DECEL_DISTANCE) {
            const t = MathUtils.clamp(distToEntry / DECEL_DISTANCE, 0, 1);
            targetSpeed = MathUtils.lerp(ORBIT_SPEED, CRUISE_SPEED, t);
        }
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, targetSpeed, delta * 3.0);

        if (distToEntry < 1.0) {
           stateRef.current = 'ORBITING';
           orbitRadiusRef.current = orbitRadius;
           const rel = new Vector3().subVectors(currentPos, targetPos);
           orbitAngleRef.current = Math.atan2(rel.z, rel.x);
           totalOrbitTraveledRef.current = 0;
        } else {
           const moveDir = new Vector3().subVectors(entryPoint, currentPos).normalize();
           groupRef.current.position.add(moveDir.multiplyScalar(currentSpeedRef.current * delta));

           // 转向平滑
           const dummy = new Object3D();
           dummy.position.copy(currentPos);
           dummy.lookAt(currentPos.clone().add(moveDir));
           groupRef.current.quaternion.slerp(dummy.quaternion, delta * 4);
        }
        break;

      case 'ORBITING':
        if (!targetObj) { stateRef.current = 'LEAVING'; break; }

        // 维持 6000 KM/H 绕飞速度
        currentSpeedRef.current = MathUtils.lerp(currentSpeedRef.current, ORBIT_SPEED, delta * 2.0);

        const angularSpeed = currentSpeedRef.current / orbitRadiusRef.current;
        orbitAngleRef.current += angularSpeed * delta;
        totalOrbitTraveledRef.current += angularSpeed * delta;

        const nextPos = new Vector3(
          targetPos.x + Math.cos(orbitAngleRef.current) * orbitRadiusRef.current,
          targetPos.y,
          targetPos.z + Math.sin(orbitAngleRef.current) * orbitRadiusRef.current
        );
        groupRef.current.position.copy(nextPos);

        // 朝向切线方向
        const tangent = new Vector3(-Math.sin(orbitAngleRef.current), 0, Math.cos(orbitAngleRef.current));
        const lookDummy = new Object3D();
        lookDummy.position.copy(nextPos);
        lookDummy.lookAt(nextPos.clone().add(tangent));
        groupRef.current.quaternion.slerp(lookDummy.quaternion, delta * 10);

        // 银行角 (侧倾模拟离心力)
        if (shipModelRef.current) {
            shipModelRef.current.rotation.z = MathUtils.lerp(shipModelRef.current.rotation.z, -0.6, delta * 2);
        }

        // 绕飞一周多后离开
        if (totalOrbitTraveledRef.current > Math.PI * 2.3) {
           stateRef.current = 'LEAVING';
           exitVectorRef.current.copy(tangent).normalize();
           leavingTimeRef.current = 0;
        }
        break;
    }

    // 更新 UI 速度显示
    setCurrentSpeedDisplay(Math.round(currentSpeedRef.current * 1000));

    // 相机跟随优化
    const shipForward = new Vector3(0, 0, 1).applyQuaternion(groupRef.current.quaternion).normalize();
    const camTarget = groupRef.current.position.clone()
        .add(shipForward.clone().multiplyScalar(-18))
        .add(new Vector3(0, 6, 0));
    state.camera.position.lerp(camTarget, 0.1);
    state.camera.lookAt(groupRef.current.position.clone().add(shipForward.multiplyScalar(8)));
  });

  const tName = missionProgress.targetName;

  return (
    <group ref={groupRef} scale={[1.5, 1.5, 1.5]}>
      {/* 飞行 HUD */}
      <Html position={[2, 1, 0]} transform sprite center>
        <div className="flex flex-col items-start pointer-events-none select-none p-3 bg-black/40 backdrop-blur-md border-l-4 border-cyan-400 skew-x-[-12deg]">
           <div className="flex flex-col mb-1">
              <span className="text-[9px] text-cyan-300 font-mono tracking-widest uppercase">Velocity</span>
              <div className="text-xl font-black text-white font-mono italic">
                 {currentSpeedDisplay.toLocaleString()}<span className="text-[10px] not-italic ml-1 opacity-70">KM/H</span>
              </div>
           </div>
           <div className="h-[1px] w-full bg-white/20 my-1"></div>
           <div className="flex flex-col">
              <span className="text-[9px] text-blue-300 font-mono tracking-widest uppercase">Target</span>
              <div className="text-sm font-bold text-white">
                 {tName.split(' ')[0] || "校准中..."}
              </div>
           </div>
        </div>
      </Html>

      {/* 模型与特效 */}
      <group ref={shipModelRef}>
        <group rotation={[Math.PI / 2, 0, 0]}>
          <mesh>
            <cylinderGeometry args={[0.3, 0.3, 1.6, 32]} />
            <meshPhysicalMaterial color="#f8fafc" metalness={0.9} roughness={0.1} clearcoat={1} />
          </mesh>
          <group position={[0, 0, 0.31]}>
             <Text color="white" fontSize={0.25} outlineWidth={0.03} outlineColor="#0891b2">{'小\n豆\n子\n号'}</Text>
          </group>
          <mesh position={[0, 1.1, 0]}>
            <coneGeometry args={[0.3, 0.6, 32]} />
            <meshPhysicalMaterial color="#f8fafc" metalness={0.9} />
          </mesh>
          <mesh position={[0, -0.85, 0]}>
            <cylinderGeometry args={[0.15, 0, 0.8, 16, 1, true]} />
            <meshBasicMaterial color="#06b6d4" transparent opacity={0.6} blending={AdditiveBlending} side={DoubleSide} />
          </mesh>
          <pointLight position={[0, -1, 0]} color="#22d3ee" intensity={3} distance={6} />
        </group>
        <group position={[0, 0, -0.8]}>
           <Trail width={0.5} length={10} color="#22d3ee" attenuation={(t) => t * t} />
        </group>
      </group>
    </group>
  );
};
